{
  "verses": [
    {
      "n": 17,
      "column": "left",
      "text": "Tà nu bija tas Nams\nîtchetrdesmitis Ohlektchu garſch/\nprohti tas Deewa Nams/ kas\npreekſch (tahs wiſſwehtakas\nWeetas) bija.\n"
    },
    {
      "n": 18,
      "column": "left",
      "text": "Eekſchpuſſê bija Zeedru-\nKohki ween pee ta Namma/ is-\ngreestì ar Pohgahin/ un atwehru\nPukkehn / wiſſ bija no Zee-\ndreem/ tà ka ne weens Akmins\nredſechts ktuã.\n"
    },
    {
      "n": 19,
      "column": "left",
      "text": "Un to Deewa Runna-\nſchanas Weetu padarrija wiſch\nNanna Widdû / to Derribas\nSchkirſtu ta KUNGA tur likt.\n"
    },
    {
      "n": 20,
      "column": "left",
      "text": "Un tahs Deewa Runna-\nſchanas Weetas Eekſchpuſſe bija\ndiwideſmits Ohlektchu Garru-\nmá/ un diwideſmits Ohlektchn\nPlattuma/ un diwideſmits Oh-\nlektchu Augstuma/ un wiſch\npahrwilke to ar tihru Seltu/\nwiſch apſitte arri to Altart ar\nZeedra Galdeem.\n"
    },
    {
      "n": 21,
      "column": "left",
      "text": "Un Salamans pahrwilke\nto ( wiſſwehtakn ) Namnu\nar tihru Seltu/ un likte ( wee-\nnu Preekſchwehkamu) ar felta\nSchkehdehm preekſch to Dee-\nwa Runnachanas Weetu / un\npahrwilke to ar Seltu.\n"
    },
    {
      "n": 22,
      "column": "left",
      "text": "Tà pahrwilke wiſch wiſ-\nfu Namnu ar Seltu/ teekains\nwiſſ tas Nams pabeigts btja/\nir wiſſu to Altari / kas preekſch\ntahs Deewa Runachanas Wee-\n"
    },
    {
      "n": 23,
      "column": "right",
      "text": "Un wiſsch darrija arrì-\ndsan tai Deewa Runnachanas\nWeeta diwi Kerubim no Etjes-\nKohka/ defmits Ohlektchu Aug-\nstumá.\n"
    },
    {
      "n": 24,
      "column": "right",
      "text": "Peezas Ohlektis bija weens\nSpahrns iklatra Keruba / no\nwiṣṣa weena Spahrna Galla\nlihds wiṣṣa ohtraim Spahrna\nGallam/ bija defmits Ohlektchu.\n"
    },
    {
      "n": 25,
      "column": "right",
      "text": "Tà patt bija arridsan tas\nohtrs Kerubs / defmits Ohlektis\nleels / pee abbeem Kerubim bija\nweens Mehrs/un weens Darbs.\n"
    },
    {
      "n": 26,
      "column": "right",
      "text": "Weens Kerubs bija def-\nmitis Ohlektis augsts/ un tà patt\narridsan tas ohtrs.\n"
    },
    {
      "n": 27,
      "column": "right",
      "text": "Un wiſsch likke tohs Ke-\nrubim ta eekſchaja Namma Wid-\ndù. Un tee Kerubim isplehte tohs\nSpahrnus/ tà ka ta weena\nSpahrns fneedse lihds weenu\nSeenu / un ta ehtra Keruba\nSpahrns fneedse lihds to ohtrn\nSeenu / bet wiṣṣu Spahrni\nNamma Widdù tikke kohpá.\n"
    },
    {
      "n": 28,
      "column": "right",
      "text": "Un wiſsch pahrwilke tohs\nKerubim ar Seltu.\n"
    },
    {
      "n": 29,
      "column": "right",
      "text": "Un wiſsch israkſtija wiſ-\nfas Naimna Seenas apkahrt /\nar isgreesteem Kerubim un Pal-\nma-Kohkein/ un atwehru Puk-\nkehn/ Eekſchpuſſe un Ahrapuſſe.\n"
    },
    {
      "n": 30,
      "column": "right",
      "text": "Wiſsch arri pahrwilke ta\nNaimna Grihdi ar Selta\nSkahrdehm/ no Eekſchpuſſes un\nno Ahrapuſſes.\n"
    },
    {
      "n": 31,
      "column": "right",
      "text": "Un kur Deewa Runna-\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
